import os
from functools import wraps
from datetime import datetime, timedelta
from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

# Load secret key from environment variable (never hardcode!)
app.config['SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY', os.urandom(32).hex())
app.config['JWT_ALGORITHM'] = 'HS256'
app.config['JWT_EXPIRATION_HOURS'] = 24

# Mock user database (replace with real database)
users_db = {
    'user1': {'password': 'password123', 'id': 1},
    'user2': {'password': 'password456', 'id': 2}
}


def generate_token(user_id, username):
    """Generate JWT token with required claims"""
    payload = {
        'user_id': user_id,
        'username': username,
        'exp': datetime.utcnow() + timedelta(hours=app.config['JWT_EXPIRATION_HOURS']),
        'iat': datetime.utcnow(),
        'iss': 'flask-api'
    }
    
    token = jwt.encode(
        payload,
        app.config['SECRET_KEY'],
        algorithm=app.config['JWT_ALGORITHM']
    )
    
    return token


def verify_token(token):
    """Verify JWT token with strict security requirements"""
    try:
        payload = jwt.decode(
            token,
            app.config['SECRET_KEY'],
            algorithms=[app.config['JWT_ALGORITHM']],
            options={
                'require': ['exp', 'iat', 'iss'],
                'verify_signature': True,
                'verify_exp': True
            },
            issuer='flask-api'
        )
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None
    except Exception:
        return None


def token_required(f):
    """Decorator to protect routes with JWT authentication"""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        
        # Get token from Authorization header
        auth_header = request.headers.get('Authorization')
        
        if auth_header:
            try:
                # Expected format: "Bearer <token>"
                token = auth_header.split(' ')[1]
            except IndexError:
                return jsonify({'message': 'Invalid token format'}), 401
        
        if not token:
            return jsonify({'message': 'Token is missing'}), 401
        
        # Verify token
        payload = verify_token(token)
        
        if payload is None:
            return jsonify({'message': 'Token is invalid or expired'}), 401
        
        # Pass user info to the route
        return f(current_user=payload, *args, **kwargs)
    
    return decorated


@app.route('/login', methods=['POST'])
def login():
    """Login endpoint to get JWT token"""
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'message': 'Username and password required'}), 400
    
    username = data['username']
    password = data['password']
    
    # Verify credentials (replace with proper password hashing in production)
    user = users_db.get(username)
    
    if not user or user['password'] != password:
        return jsonify({'message': 'Invalid credentials'}), 401
    
    # Generate token
    token = generate_token(user['id'], username)
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'expires_in': app.config['JWT_EXPIRATION_HOURS'] * 3600
    }), 200


